// Package models holds the registry of NVIDIA build.nvidia.com playground
// models and their reverse-engineered NVCF invocation parameters.
//
// The build.nvidia.com playground calls
//
//	POST https://api.ngc.nvidia.com/v2/predict/models/{namespace}/{slug}
//	              nv-function-id: {functionID}
//	              nv-captcha-token: <hCaptcha token>
//
// Each playground model has its own {slug} and nv-function-id. The {namespace}
// is currently shared across all playground models (qc69jvmznzxy). The map
// below is generated by scripts/scrape_playground_models.py: it fetches the
// anonymous model list from https://integrate.api.nvidia.com/v1/models and, for
// each id, scrapes https://build.nvidia.com/{id}/playground for the server-
// rendered "nvcfFunctionId" + "namespace". Models whose playground page does
// not inline a function id are skipped (see the script's skipped list).
//
// To regenerate the data, run
//
//	python3 scripts/scrape_playground_models.py > scripts/playground_models.json
//
// then refresh the Models map (the slug/namespace/functionID triple per id).
package models

import "fmt"

// Namespace is the NVCF namespace embedded in every playground predict URL.
// All known sandbox models currently share this one namespace.
const Namespace = "qc69jvmznzxy"

// ModelInfo is the per-model NVCF invocation data needed to call the
// (anonymous, hCaptcha-gated) playground predict endpoint.
type ModelInfo struct {
	// Slug is the model name segment used in the predict URL path
	// (everything after the last "/"). E.g. "glm-5.2" for "z-ai/glm-5.2".
	Slug string
	// Namespace is the NVCF namespace for this model. Currently always
	// Namespace, but kept per-model in case NVIDIA splits sandboxes.
	Namespace string
	// FunctionID is the nv-function-id header value (per-model UUID).
	FunctionID string
}

// PredictEndpoint returns the predict URL for a model info.
func (m ModelInfo) PredictEndpoint() string {
	return "https://api.ngc.nvidia.com/v2/predict/models/" + m.Namespace + "/" + m.Slug
}

// DefaultModel is the project's default playground model (kept for backward
// compatibility with pre-multi-model callers).
const DefaultModel = "z-ai/glm-5.2"

